var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"여기 있었군요, 리벳.","JPN":"ここにいたのですね、リベット。","ENG":"There you are, Rivet.","TWN":"你在這兒啊，里維。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L5_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"얼레? 나 안 죽었네?","JPN":"あれ？　アタシ、死んでない？","ENG":"Huh? I'm not dead?","TWN":"哎呀？我沒死啊？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L6_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아니면 여기가 혹시 천국인 건가? 천국에는 어떻게 기어 올라온 거야, 레지나?","JPN":"それとも、もしかしてここ天国？　天国にはどうやって這い上がってきたんだよ、レジーナ。","ENG":"Wait... Am I in heaven? But how did you get up here too, Regina?","TWN":"還是說這裡是天堂？你是怎麼上天堂的，蕾佳娜？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"뻔뻔하네요. 천국과 제일 거리가 먼 주제에.","JPN":"図々しいですわね。天国とは一番縁遠いくせに。","ENG":"How shameless of you, Rivet. You are the only person who has no chance of ever entering heaven.","TWN":"真是厚臉皮。一個距離天堂最遠的人，還好意思說什麼天堂。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"왜 이래. 난 법 없이도 살 사람이잖아.","JPN":"何だよ。アタシは法がなくても生きていける人じゃない？","ENG":"What do you mean? You know I'm someone who’s better off without rules.","TWN":"幹嘛呀，我可是個自任守法的人。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_SERIOUS2"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L9_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"후우……. 입만 살아선.","JPN":"ふう……よく言いますね。","ENG":"*Sigh...* Again with your sly tongue...","TWN":"哀……油嘴滑舌。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L10_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"상태가 심각해서 생물학부장이 소지하고 있던 엘릭서를 투여했어요. 기분은 좀 어떤가요.","JPN":"状態がひどかったので、生物学部長が所持していたエリクサーを投与しました。気分はどうですか？","ENG":"Because your condition was critical, I used the Elixir that the Dean of Biology had on him. How are you feeling?","TWN":"我看你傷勢很嚴重，就給你用了生物學院院長手裡的聖水。你感覺怎麼樣。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L11_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"나 머리에서 뿔이 삐죽삐죽 돋아날 것 같아.","JPN":"頭から角ツンツン生えてきそうだよ。","ENG":"I feel like horns are going to sprout from my head.","TWN":"我感覺頭上好像要長出角了。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_HATE"}}}},{"id":"L12_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"아앗! 피부가 레지나 성질머리처럼 까칠까칠해! 융합체로 변하나 봐!","JPN":"ああっ！　肌がレジーナの性格みたいに悪くなってる！　融合体になってるのかも！","ENG":"Oww! My skin is all grizzly like Regina's temper! Maybe I'm turning into a hybrider!","TWN":"啊啊！皮膚也變得像蕾佳娜的壞脾氣一樣粗糙了！我好像要變成融合體了！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L13_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그냥 각질이겠죠.","JPN":"ただの角質でしょう。","ENG":"That is just your flaking skin.","TWN":"應該就是角質吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L14_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"그런데 그 생물학부장은 어디 갔어? 엘릭서만 바치고 꽁무니 뺄 사람은 아니던데?","JPN":"ていうか、あの生物学部長はどこに行ったの？　エリクサーだけ捧げて逃げるような人じゃなさそうだったけど。","ENG":"But where's the Dean of Biology? I don't think he's the type to simply give up an Elixir and run.","TWN":"不過那個生物學院院長去哪兒了？他可不像是會獻出聖水，然後夾著尾巴逃走的人？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L15_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"특정 공간에 존재하는 분자의 운동 에너지를 인위적으로 즉각 정지시킬 수 있다면 어떻게 될지, 상상해 본 적 있나요?","JPN":"特定空間に存在する分子の運動エネルギーを、人為的に即時停止させることができたらどうなるか、想像してみたことはありますか？","ENG":"Have you ever wondered what would happen if you could suddenly and artificially stop the kinetic energy of molecules in a specific space?","TWN":"如果可以人為地停止存在於特定空間裡的分子動能會怎麼樣，你想像過嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_LAUGH"}}}},{"id":"L16_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"몰라!","JPN":"わかんない！","ENG":"Nope!","TWN":"不知道！"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"그러면 그냥 사라지게 했다고 하죠.","JPN":"じゃあ、ただ消したと言っておきましょう。","ENG":"Then, let's say I simply made him disappear.","TWN":"那你就當他消失了吧。"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L18_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"호오…….","JPN":"おお……","ENG":"Ooh...","TWN":"呼……"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_PRIDE"}}}},{"id":"L19_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"실키랑 작별 인사는 잘 나눴어?","JPN":"シルキーとはちゃんとお別れできた？","ENG":"Did you say your goodbyes with Sylkie?","TWN":"你跟思琪好好告別了？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L20_1","type":"dialog","speaker":"REGINA_ESPR_NEXT_NULL","text":{"KOREA":"역시 처음부터 눈치채고 있었군요. 왜 말 안 했죠?","JPN":"やはり最初から気付いていたのですね。どうして言わなかったのですか？","ENG":"So you did know about her. Why did you not tell me?","TWN":"你果然從一開始就發現了。你為什麼沒說？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}},{"id":"L21_1","type":"dialog","speaker":"RIVET_ESPR_ReinforcedA_NULL","text":{"KOREA":"사장님 쪽도 마찬가지 아니었을까? 뒤늦게 알아채는 편이 웃기잖아?","JPN":"社長も同じじゃないのかな？　後で気付いた方が面白いでしょ？","ENG":"Maybe for the same reason Boss didn't? It'd be funny if you found out later!","TWN":"老闆不是也沒說嗎？等你晚一點才看出來，不是更好笑嗎？"},"stage":{"bg":"COUNTERSIDE_FOREST_NIGHT","slots":{"L":{"char_id":"REGINA_ESPR_NEXT_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"RIVET_ESPR_ReinforcedA_NULL","face":"UNIT_IDLE"}}}}]`);export{e as default};